          height="16"
          viewBox="0 0 16 16"
          fill="none"
        >
          <circle cx="8" cy="8" r="7" fill="currentColor" opacity="0.2" />
          <path
            d="M8 5V5.01M8 7V11"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
          />
        </svg>
      );
  }
}

export function Toast({ style, title, message, onDismiss }: ToastProps) {
